        },
        excluded_sections: {
          type: 'array',
          items: {
            type: 'object',
            properties: {
              file: { type: 'string' },
              section_id: { type: 'string' },
              reason: { type: 'string' }
            },
            required: ['file', 'section_id', 'reason']
          }
        }
      },
      required: ['selected_pages', 'excluded_pages', 'selected_sections', 'excluded_sections']
    }
  }
)

phase('ReadSections')

// Select sections: all high first, then partial, max 10
const highSections = searchResult.selected_sections.filter(s => s.relevance === 'high')
const partialSections = searchResult.selected_sections.filter(s => s.relevance === 'partial')
const sectionsToRead = [...highSections, ...partialSections].slice(0, 10)

const readArgs = sectionsToRead.map(s => `"${s.file}:${s.section_id}"`).join(' ')

const sectionsContent = await agent(
  `Run this bash command and return the complete output:

bash /home/tie303177/work/nabledge/work2/.claude/skills/nabledge-6/scripts/read-sections.sh ${readArgs}

Return the raw output text exactly as produced.`,
  {
    label: 'read-sections',
    phase: 'ReadSections'
  }
)

return {
  searchResult,
  sectionsToRead,
  sectionsContent
}

